invalid = {'case_id': 'CASO-ARE-041-1A', 'created': True, 'method': 'POST', 'resource': '/v1/jobs', 'status': 200}
incomplete = {**valid}
incomplete.pop('status', None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

